// Build the /process payload from the IMAP email.
// Email body is parsed for structured manual fields (key: value lines).
// Attachments are turned into base64 documents.

const item = items[0].json;
const binary = items[0].binary || {};

// --- Parse manual fields from email body ---
const body = (item.textPlain || item.text || '').toString();
const FIELD_KEYS = [
  'marital_status', 'nationality', 'caste',
  'mobile_number', 'correspondence_address',
  'correspondence_pin_code', 'disability_status'
];
const manual = {};
for (const key of FIELD_KEYS) {
  const re = new RegExp('^\\s*' + key.replace(/_/g, '[ _-]') + '\\s*[:=]\\s*(.+)$', 'im');
  const m = body.match(re);
  if (m) manual[key] = m[1].trim();
}
manual.email = item.from?.value?.[0]?.address || item.from || '';

// --- Collect attachments ---
const documents = [];
for (const [key, att] of Object.entries(binary)) {
  documents.push({
    filename: att.fileName || key,
    content_base64: att.data,
    mime_type: att.mimeType || 'application/octet-stream'
  });
}

const userEmail = item.from?.value?.[0]?.address || item.from || 'unknown@unknown';

return [{
  json: {
    user_id: userEmail,
    email: userEmail,
    documents,
    manual_fields: manual,
    attempt_number: 1
  }
}];

// Build follow-up email body from attempt #1 template (inline so n8n has no file deps).
const d = items[0].json;
const missing = (d.missing_fields || []).map(f => '  - ' + f).join('
') || '  (none)';
const errs = (d.validation_errors || []).map(e => `  - [${e.code}] ${e.detail}`).join('
') || '  (none)';
const name = d.extracted?.name || 'there';

const subject = 'Action needed: a few details are missing for your exam application';
const text = `Hi ${name},

Thanks for sending your documents to EasyForm. We tried to auto-fill your exam application
but couldn't complete it because of the items below. Please reply to this email with the
missing information so we can finish the form for you.

--- Information we still need ---
${missing}

--- Issues with the documents you sent ---
${errs}

Please reply within 6 hours so we can keep your application on track. We'll send one
follow-up if we don't hear from you.

Reference ID: ${d.user_id}

— EasyForm`;

return [{ json: { ...d, _email_subject: subject, _email_text: text } }];
